class Solution:
    def makeTheIntegerZero(self, num1: int, num2: int) -> int:
        if num2 >= 0:
            if num1 % num2 == 0:
                return num1 // num2
            else:
                return -1
        elif num2 == 0:
            return -1 if num1 != 0 else 0
        operations = 0
        while num1 > 0:
            if num1 >= 60:
                diff = num1 - (num1 % abs(num2))
                operations += diff // abs(num2)
                num1 = num1 % abs(num2)
            else:
                for i in range(60, -1, -1):
                    if (1 << i) + num2 > 0 and num1 >= (1 << i) + num2:
                        num1 -= (1 << i) + num2
                        operations += 1
                        break
                else:
                    return -1
        return operations
